<template>
  <q-page class="items-center justify-evenly">
  <q-col>
    <q-row>
        <q-dialog v-model="icon">
        <q-card>
            <ModelForm v-bind:model="modelObj" v-bind:adminservice="adminService" v-bind:service="service"/>
        </q-card>
      </q-dialog>
        <q-btn :label="$t('new_row')" color="primary" @click="icon = true" />
      </q-row>
      <q-row>
<!-- I need a dialog for Uploader-->
        <q-dialog v-model="populateDialog">
        <q-card>
            <Uploader v-bind:population="{'service':service}"/>
        </q-card>
      </q-dialog>
      <q-btn :label="$t('populate')" color="primary" @click="populateDialog = true" />
      </q-row>
      <q-space />
      <q-row>
        <ModelTable v-bind:model="modelObj" v-bind:adminservice="adminService" v-bind:service="service" />
      </q-row>
    </q-col>
  </q-page>
</template>

<script lang="ts">
import { defineComponent, ref } from 'vue';
import ModelTable from '../components/ModelTable.vue';
import ModelForm from '../components/ModelForm.vue';
import {default as ModelRegistry} from '../models'
import {AdminService} from '../services/admin'
import { Service } from '../services/base'
import Uploader from '../components/Uploader.vue'

const models = ModelRegistry.getInstance().getModels()

export default defineComponent({
  name: 'DataTablePage',
    components: {
        ModelTable,
        Uploader,
        ModelForm
    },
  props: {
  },
  data(){
    return {
      icon: false,
      serviceType:'',
      populateDialog:false,
    }
  },
  computed: {
    modelObj(){
      let modelname=this.$route.params.model
      modelname=modelname.split("-").map((part,i) => part.charAt(0).toUpperCase() + part.slice(1) ).join("")
      console.log(modelname)
      return new models[modelname]()
    },
    service(){
      let model=this.$route.params.model.split("-").map((part,i) => part.charAt(0).toUpperCase() + part.slice(1) ).join("")
      return new Service(model) 
    },
    adminService(){
      return new AdminService()
    }
  },
  async created(){
  }
});
</script>
